func (o *AdministratorResourceModel) CopyToPango(ctx context.Context, client pangoutil.PangoClient, ancestors []Ancestor, obj **administrator.Entry, ev *EncryptedValuesManager) diag.Diagnostics {
	var diags diag.Diagnostics
	authenticationProfile_value := o.AuthenticationProfile.ValueStringPointer()
	clientCertificateOnly_value := o.ClientCertificateOnly.ValueBoolPointer()
	passwordProfile_value := o.PasswordProfile.ValueStringPointer()
	var permissions_entry *administrator.Permissions
	if !o.Permissions.IsUnknown() && !o.Permissions.IsNull() {
		if *obj != nil && (*obj).Permissions != nil {
			permissions_entry = (*obj).Permissions
		} else {
			permissions_entry = new(administrator.Permissions)
		}
		var object *AdministratorResourcePermissionsObject
		diags.Append(o.Permissions.As(ctx, &object, basetypes.ObjectAsOptions{})...)
		if diags.HasError() {
			return diags
		}
		diags.Append(object.CopyToPango(ctx, client, ancestors, &permissions_entry, ev)...)
		if diags.HasError() {
			return diags
		}
	}

	var password_value *string
	{
		valueKey, err := CreateXpathForAttributeWithAncestors(ancestors, "password")
		if err != nil {
			diags.AddError("Failed to create encrypted values state key", err.Error())
			return diags
		}
		stateValue, found := ev.GetPlaintextValue(valueKey)
		if !found || stateValue != o.Password.ValueString() {
			hashed, err := administratorCreatePasswordHash(ctx, client, o.Password.ValueString())
			if err != nil {
				diags.AddError("Failed to hash sensitive value", err.Error())
				return diags
			}

			err = ev.StoreEncryptedValue(valueKey, "client", hashed)
			if err != nil {
				diags.AddError("Failed to manage encrypted values state", err.Error())
				return diags
			}

			err = ev.StorePlaintextValue(valueKey, "client", o.Password.ValueString())
			if err != nil {
				diags.AddError("Failed to manage encrypted values state", err.Error())
				return diags
			}

			password_value = &hashed
		} else {
			password_value = &stateValue
		}
	}
	var preferences_entry *administrator.Preferences
	if !o.Preferences.IsUnknown() && !o.Preferences.IsNull() {
		if *obj != nil && (*obj).Preferences != nil {
			preferences_entry = (*obj).Preferences
		} else {
			preferences_entry = new(administrator.Preferences)
		}
		var object *AdministratorResourcePreferencesObject
		diags.Append(o.Preferences.As(ctx, &object, basetypes.ObjectAsOptions{})...)
		if diags.HasError() {
			return diags
		}
		diags.Append(object.CopyToPango(ctx, client, ancestors, &preferences_entry, ev)...)
		if diags.HasError() {
			return diags
		}
	}
	publicKey_value := o.PublicKey.ValueStringPointer()

	if (*obj) == nil {
		*obj = new(administrator.Entry)
	}
	(*obj).Name = o.Name.ValueString()
	(*obj).AuthenticationProfile = authenticationProfile_value
	(*obj).ClientCertificateOnly = clientCertificateOnly_value
	(*obj).PasswordProfile = passwordProfile_value
	(*obj).Permissions = permissions_entry
	(*obj).Phash = password_value
	(*obj).Preferences = preferences_entry
	(*obj).PublicKey = publicKey_value

	return diags
}
